sql:
SELECT page_id, last_access_date
FROM memory_card_pages
WHERE access_count > 5;

SELECT release_date
FROM memory_card_formats
ORDER BY release_date DESC;

SELECT image_name
FROM memory_card_images
WHERE status = 'active';

SELECT COUNT(*) AS bad_block_count
FROM bad_blocks
WHERE format_id = 1;

SELECT mcf.description
FROM bad_blocks bb
JOIN memory_card_formats mcf ON bb.format_id = mcf.format_id;

SELECT page_id, access_count
FROM memory_card_pages
ORDER BY access_count DESC;

SELECT version, release_date
FROM memory_card_formats
WHERE format_id = 1;

SELECT format_id, release_date
FROM memory_card_formats
ORDER BY release_date DESC;

SELECT version
FROM memory_card_formats
WHERE release_date > '2022-01-01';

SELECT MAX(access_count) AS max_access_count
FROM memory_card_pages
WHERE is_bad = 0;

external_knowledge:
- 'Healthy pages' refer to those with the 'is_bad' flag set to 0;
- 'Active blocks' are those with a status of 'active';
- 'Unresolved bad block issues' are those with 'bad_block_is_fixed' set to 0 or NULL;
- 'Most frequently accessed' refers to pages with a higher 'access_count'.

sql:
SELECT format_id
FROM memory_card_formats
WHERE page_size = (SELECT MAX(page_size) FROM memory_card_formats);

SELECT COUNT(*) AS active_image_count
FROM memory_card_images
WHERE status = 'active';
